// apiService.js

const BASE_URL = 'https://api.example.com';

// Token storage (in a real app, use AsyncStorage or SecureStore)
let authToken = null;
let refreshToken = null;

// ============ Token Management ============

const setTokens = (access, refresh) => {
  authToken = access;
  refreshToken = refresh;
};

const clearTokens = () => {
  authToken = null;
  refreshToken = null;
};

const getAuthToken = () => authToken;
const getRefreshToken = () => refreshToken;

// ============ Request Helper ============

const DEFAULT_HEADERS = {
  'Content-Type': 'application/json',
  'Accept': 'application/json',
};

const buildHeaders = (requiresAuth = true, customHeaders = {}) => {
  const headers = { ...DEFAULT_HEADERS, ...customHeaders };
  if (requiresAuth && authToken) {
    headers['Authorization'] = `Bearer ${authToken}`;
  }
  return headers;
};

// Custom API Error class
class ApiError extends Error {
  constructor(message, status, data) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
    this.data = data;
  }
}

// Generic request function with timeout, retry, and token refresh
const request = async (
  endpoint,
  {
    method = 'GET',
    body = null,
    requiresAuth = true,
    customHeaders = {},
    timeout = 15000,
    retries = 1,
  } = {}
) => {
  const url = `${BASE_URL}${endpoint}`;

  const options = {
    method,
    headers: buildHeaders(requiresAuth, customHeaders),
  };

  if (body && method !== 'GET') {
    options.body = JSON.stringify(body);
  }

  // Implement timeout using AbortController
  const controller = new AbortController();
  options.signal = controller.signal;
  const timeoutId = setTimeout(() => controller.abort(), timeout);

  let lastError = null;

  for (let attempt = 0; attempt <= retries; attempt++) {
    try {
      const response = await fetch(url, options);
      clearTimeout(timeoutId);

      // Handle token refresh on 401
      if (response.status === 401 && requiresAuth && attempt === 0) {
        const refreshed = await attemptTokenRefresh();
        if (refreshed) {
          // Retry the original request with new token
          options.headers = buildHeaders(requiresAuth, customHeaders);
          const retryResponse = await fetch(url, options);
          return await handleResponse(retryResponse);
        } else {
          clearTokens();
          throw new ApiError('Session expired. Please log in again.', 401, null);
        }
      }

      return await handleResponse(response);
    } catch (error) {
      clearTimeout(timeoutId);
      lastError = error;

      if (error.name === 'AbortError') {
        throw new ApiError('Request timed out. Please check your connection.', 0, null);
      }

      if (error instanceof ApiError) {
        throw error;
      }

      // Retry on network errors
      if (attempt < retries) {
        await delay(1000 * (attempt + 1)); // Exponential-ish backoff
        continue;
      }
    }
  }

  throw lastError || new ApiError('Network request failed.', 0, null);
};

const handleResponse = async (response) => {
  let data = null;

  const contentType = response.headers.get('content-type');
  if (contentType && contentType.includes('application/json')) {
    data = await response.json();
  } else {
    data = await response.text();
  }

  if (!response.ok) {
    const errorMessage =
      (data && data.message) ||
      (data && data.error) ||
      `Request failed with status ${response.status}`;
    throw new ApiError(errorMessage, response.status, data);
  }

  return {
    data,
    status: response.status,
    headers: response.headers,
  };
};

const delay = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

// ============ Token Refresh ============

const attemptTokenRefresh = async () => {
  if (!refreshToken) return false;

  try {
    const response = await fetch(`${BASE_URL}/auth/refresh`, {
      method: 'POST',
      headers: DEFAULT_HEADERS,
      body: JSON.stringify({ refreshToken }),
    });

    if (response.ok) {
      const data = await response.json();
      setTokens(data.accessToken, data.refreshToken);
      return true;
    }
    return false;
  } catch {
    return false;
  }
};

